#include<bits/stdc++.h>
using namespace std;
int n,m,cnt[101];
int dp[2000010],a[1000010];
int sum[100010][21];
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        cnt[a[i]]++;
        for(int j=1;j<=m;j++)
        {
            if(a[i]==j)
            {
                sum[i][j]=sum[i-1][j]+1;
            }
            else
            {
                sum[i][j]=sum[i-1][j];
            }
        }
    }
    memset(dp,0x3f,sizeof(dp));
    dp[0]=0;
    for(int i=0;i<(1<<m);i++)
    {
        int sum1=0;
        for(int j=1;j<=m;j++)
        {
            if(i&(1<<(j-1)))
            {
                sum1+=cnt[j];
            }
        }
        for(int j=1;j<=m;j++)
        {
            if(!(i&(1<<(j-1))))
            {
                int l=sum1+1,r=sum1+cnt[j];
                dp[i|(1<<(j-1))]=min(dp[i|(1<<(j-1))],dp[i]+cnt[j]-sum[r][j]+sum[l-1][j]);
            }
        }
    }
    printf("%d",dp[(1<<m)-1]);
    return 0;
}
